-- ten_companies_per_service.sql
-- Generated by scripts/build-companies-seed.cjs
-- Adds verified real Canadian (Ontario-preferred) commercial kitchen
-- equipment companies so every /services/[slug] category lists >=10
-- suppliers (Price Match kept truthful at 7). All ranking composites are
-- below Shop at Stop (9.4); S.T.O.P remains the #1 listing.

begin;

-- Silence the per-row deploy-hook during the bulk load; the merge/deploy
-- to main rebuilds the SSG site once from the new data.
alter table public.companies disable trigger trg_company_changed;

-- Truthful correction: remove unsupported Price Match tags.
update public.companies set services = ARRAY['Commercial Equipment Procurement', 'Equipment Consulting']::text[] where slug = 'nella-cutlery';
update public.companies set services = ARRAY['Commercial Equipment Procurement']::text[] where slug = 'chefco';
update public.companies set services = ARRAY['Commercial Equipment Procurement']::text[] where slug = 'igloo-food-equipment';

