  ARRAY['Commercial Equipment Procurement', 'Equipment Financing', 'Equipment Leasing', 'Installation Services', 'Account Management', 'Equipment Consulting']::text[],
  '{}'::text[],
  '[]'::jsonb, false, '{"service_range":8,"customer_reviews":7.5,"industry_experience":8,"response_time":7.5,"pricing_transparency":7,"certifications":7}'::jsonb
